import { describe, expect, it } from 'vitest';

import { Pipeline } from '../pipeline';
import type { IStation } from '../types';

const HIDDEN_DIM = 4;
const VOCAB_SIZE = 8;

interface CallCounts {
  embed: number;
  forward: number;
  lmHead: number;
  sampleNext: number;
  decodeNext: number;
  generateTokens: number;
}

function buildStation(): { station: IStation; calls: CallCounts } {
  const calls: CallCounts = {
    embed: 0,
    forward: 0,
    lmHead: 0,
    sampleNext: 0,
    decodeNext: 0,
    generateTokens: 0,
  };

  const station: IStation = {
    startLayer: 0,
    endLayer: 1,
    role: 'entry',
    maxBatchSize: 8,

    async embed({ tokens }) {
      calls.embed += 1;
      return new Float32Array(tokens.length * HIDDEN_DIM).fill(0.1);
    },

    async forward({ residual }) {
      calls.forward += 1;
      return { residual };
    },

    async lmHead() {
      calls.lmHead += 1;
      const logits = new Float32Array(VOCAB_SIZE);
      logits[5] = 1;
      return logits;
    },

    async sampleNext() {
      calls.sampleNext += 1;
      return 5;
    },

    async decodeNext() {
      calls.decodeNext += 1;
      return 6;
    },

    async generateTokens() {
      calls.generateTokens += 1;
      return new Uint32Array([7, 6]);
    },

    async cobordismEmbed() {
      throw new Error('not used');
    },

    async cobordismLmHead() {
      throw new Error('not used');
    },

    async bizarroForward() {
      return null;
    },
  };

  return { station, calls };
}

describe('Pipeline native generate shortcut', () => {
  it('uses native generateTokens for a single station by default', async () => {
    const { station, calls } = buildStation();
    const pipeline = new Pipeline({
      stations: [station],
      hiddenDim: HIDDEN_DIM,
      vocabSize: VOCAB_SIZE,
    });

    const out = await pipeline.generate({
      promptTokens: new Uint32Array([1, 2]),
      maxNewTokens: 2,
    });

    expect([...out]).toEqual([1, 2, 7, 6]);
    expect(calls.generateTokens).toBe(1);
    expect(calls.embed).toBe(0);
    expect(calls.decodeNext).toBe(0);
  });

  it('bypasses native generateTokens when disabled', async () => {
    const { station, calls } = buildStation();
    const pipeline = new Pipeline({
      stations: [station],
      hiddenDim: HIDDEN_DIM,
      vocabSize: VOCAB_SIZE,
      disableNativeGenerate: true,
    });

    const out = await pipeline.generate({
      promptTokens: new Uint32Array([1, 2]),
      maxNewTokens: 2,
    });

    expect([...out]).toEqual([1, 2, 5, 6]);
    expect(calls.generateTokens).toBe(0);
    expect(calls.embed).toBe(1);
    expect(calls.lmHead).toBe(1);
    expect(calls.sampleNext).toBe(0);
    expect(calls.decodeNext).toBe(1);
  });
});
